mkdir -p build
emcc -O3 -fwasm-exceptions -o build/analyze.js native/analyze.cpp -s NO_EXIT_RUNTIME=1 -s EXPORTED_FUNCTIONS='["_free", "_malloc", "_getNodeCount7x6", "_getNodeCountHeuristic7x6"]' -s EXPORTED_RUNTIME_METHODS='["FS", "UTF8ToString", "stringToNewUTF8", "getValue", "wasmMemory"]' -s INITIAL_MEMORY=200MB -s ALLOW_MEMORY_GROWTH -s WASM=1 -s SINGLE_FILE=1 -s MODULARIZE=1 -s EXPORT_NAME="createModule"

emcc -O3 -fwasm-exceptions -DUSE_PTHREADS=1 -pthread -o build/analyze_threaded.js native/analyze.cpp -s NO_EXIT_RUNTIME=1 -s EXPORTED_FUNCTIONS='["_free", "_malloc", "_getNodeCount7x6", "_getNodeCountHeuristic7x6"]' -s EXPORTED_RUNTIME_METHODS='["FS", "UTF8ToString", "stringToNewUTF8", "getValue", "wasmMemory"]' -s INITIAL_MEMORY=200MB -s MAXIMUM_MEMORY=1GB -s ALLOW_MEMORY_GROWTH -s WASM=1 -s SINGLE_FILE=1 -s MODULARIZE=1 -s EXPORT_NAME="createThreadedModule" -s PTHREAD_POOL_SIZE=12